  ('disabled-57f41407-moex-00747', 'disabled-57f41407', 'disabled-57f41407-moex-110-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲駕駛車輛因過失撞傷行人乙，於有偵查犯罪權限之機關，尚不知肇事者 為何人之前，甲向到場處理事故之警員坦承其為肇事人，甲所犯之過失傷 害罪，適用刑法減輕其刑之依據為何？', '["依法令之行為", "自首", "自白", "緊急避難"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "5db5447f7cf3", "answer_pdf_sha1": "7fcda6220c2a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
