  ('disabled-57f41407-moex-00750', 'disabled-57f41407', 'disabled-57f41407-moex-110-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲犯違背職務收受賄賂罪後，於有偵查犯罪權限之機關尚未發覺犯罪前， 主動向司法警察機關坦承犯罪自首，並繳交犯罪所得新臺幣 30 萬元，法 院於審理時應如何裁判？', '["應減輕或免除其刑", "得減輕或免除其刑", "應減輕其刑", "得減輕其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "5db5447f7cf3", "answer_pdf_sha1": "7fcda6220c2a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
